---播放子弹
---@class LBattleSkillActBullet
local LBattleSkillActBullet = classX("LBattleSkillActBullet", nil)


---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActBullet.Execute(player,effData, playState)
    local effTarget = effData.effTarget

    if effTarget == LFightConst.EFFECT_TO_EVERY_TAR then
        LBattleSkillActBullet.ExecuteTargetBullet(player, effData,playState)
    else
        LBattleSkillActBullet.ExecuteNormalBullet(player, effData,playState)
    end
end

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActBullet.ExecuteTargetBullet(player, effData,playState)
    local obj = player:GetTargetAtkUnitView()
    local effRes = effData.effRes --光效名字
    --local effTarget = effData.effTarget
    local moveSpeed = effData.moveSpeed * 0.01 -- 子弹飞行速度(配置表是像素这里要转换成米)
    local bulletTrack = effData.bulletTrack -- 子弹飞行轨迹
    local dissipateTime = effData.dissipateTime --光效消散时间
    local offsetStart = effData.effOffsetStart --偏移
    local bulletCdTime = effData.bulletCdTime or 0 --多个子弹的延迟射出间隔
    local playNum = effData.playNum or {} --单个子弹分解次数
    local excursionIObject = effData.excursionIObject or 0
    local offsetEnd = effData.effOffsetEnd
    local effStartType = effData.effStartType or 1

    local _viewMgr = player:GetViewMgr()
    local _heroOffsetPointList = player:GetHeroOffsetPointList()

    if moveSpeed < 0 then
        if LOG_INFO_ENABLED then
            printError("battle", "wrong speed %s", tostring(effData.refId))
        end
        moveSpeed = 1
    end

    local dataList = {}
    local bulletDataList = LBattleSkillActBullet.FormatBulletData(player, effData)
    if bulletDataList then
        for k,v in ipairs(bulletDataList) do
            for k1,v1 in ipairs(v) do
                local tempData = player:FormatEffectData(effData,v1)
                if tempData then
                    local groupIndex = v1.groupIndex
                    local groupDataList = dataList[groupIndex] or {}
                    dataList[groupIndex] = groupDataList
                    table.insert(groupDataList,tempData)
                end
            end
        end
    end

    local effectCtrl = _viewMgr:GetEffectCtrl()
    local atkDir = obj:GetDirection()
    local atkPos = obj:GetPosition()
    local atkSide = obj:GetTeamIdx()
    local effectRootTrans = _viewMgr:GetEffectRootTrans()
    --
    --local startPos = nil
    ----朝左
    --if atkDir == LFightConst.DIRECTION_LEFT then
    --	startPos = Vector3(atkPos.x - offsetStart.x, atkPos.y + offsetStart.y, 0)
    --else
    --	--朝右
    --	startPos = Vector3(atkPos.x + offsetStart.x, atkPos.y + offsetStart.y, 0)
    --end

    for k,v in ipairs(dataList) do

        local isShow = false  ---客户端多段飘血 只有一个子效果
        local curBulletCdTime = 0
        --子弹都是从自身位置创建，跟自身方向相同
        for k1,v1 in ipairs(v) do
            local bulletData = v1.bulletData
            local tarId = bulletData.tarId
            local tarObj = _viewMgr:GetUnitView(tarId)
            local targetPos = tarObj:GetPosition():Clone()
            local defaultPos = player:GetEffStartPos(effStartType,atkSide,atkPos,targetPos)
            local startPos = nil
            if atkDir == LFightConst.DIRECTION_LEFT then
                --朝左
                startPos = Vector3(defaultPos.x - offsetStart.x, defaultPos.y + offsetStart.y, 0)
            else
                --朝右
                startPos = Vector3(defaultPos.x + offsetStart.x, defaultPos.y + offsetStart.y, 0)
            end


            local offset = Vector3.zero
            --受击的 和 攻击的朝向相反的
            if atkDir == LFightConst.DIRECTION_RIGHT then
                offset.x = - offsetEnd.x
            else
                offset.x =  offsetEnd.x
            end

            if excursionIObject == 1 then
                local randomNum = _heroOffsetPointList[math.random(1,5)]  -- 目标人物偏移值，策划没有设置effOffsetEnd的前提下，0.1-0.3的区间范围：脚底，躯干，头顶
                offset.y = randomNum
            else
                offset.y = offsetEnd.y
            end

            --弹道落点
            local endPos = v1.pos + offset
            endPos.z = 0

            --弹道落点
            local point = endPos:Clone()

            local scale = player:GetScale()
            if scale and scale > 1 then
                startPos.y = startPos.y * scale
            end

            --计算出时间
            local moveTime = (Vector3.Distance(startPos, endPos) / moveSpeed)

            local effect = effectCtrl:MakeBattleSkillEffectObj(effectRootTrans, effRes, startPos, atkDir, curBulletCdTime, moveTime, dissipateTime)
            effect:SetBullet(true, endPos, moveTime, bulletTrack,k1)
            local para =
            {
                isUpperLayer= player:IsUpperLayer(tarId),
                scale = scale
            }
            effect:SetEffectPara(para)
            effectCtrl:AddEffect(effect)

            moveTime = moveTime + curBulletCdTime


            local hurtDataType =bulletData.hurtDataType
            local hurtDataIndex = bulletData.hurtDataIndex

            if hurtDataType == 1 then --客户端表现多段
                bulletCdTime = k <= #playNum and playNum[k] or playNum[#playNum]
                -- 单个目标多个子弹的延迟射出间隔
                curBulletCdTime = curBulletCdTime + bulletCdTime
            elseif hurtDataType == 2 then
                -- 多个目标的子弹的延迟射出间隔
                curBulletCdTime = curBulletCdTime + bulletCdTime
            elseif hurtDataType == 3 then
                curBulletCdTime = 0
            end

            local tarId = bulletData.tarId
            local childList = playState.childList
            local nextPlayList = effData.nextPlayList
            if childList then
                local startTime = playState.startTime

                for k2,v2 in ipairs(nextPlayList) do
                    if v2.effType == LSkillEffConst.PLAY_EFF_HIT_HUD or v2.effType == LSkillEffConst.PLAY_EFF_HUD then
                        if not isShow then
                            local childStartTime = startTime + moveTime + v2.delayTime
                            local childEndTime = childStartTime + v2.playTime
                            local childPlayState = player:GenerateChildPlayState(v2, childStartTime, childEndTime)
                            childPlayState.isTarBullet = true
                            childPlayState.tarId = tarId
                            childPlayState.hurtDataType = hurtDataType
                            childPlayState.hurtDataIndex = hurtDataIndex
                            childPlayState.bulletTarPos = point
                            childPlayState.groupIndex = k
                            table.insert(childList, childPlayState)
                        end

                        if hurtDataType == 1 and not isShow then --客户端多段飘血,只剩生成一个飘血
                            isShow = true
                        end
                    else
                        local childStartTime = startTime + moveTime + v2.delayTime
                        local childEndTime = childStartTime + v2.playTime
                        local childPlayState = player:GenerateChildPlayState(v2, childStartTime, childEndTime)
                        childPlayState.isTarBullet = true
                        childPlayState.tarId = tarId
                        childPlayState.bulletTarPos = offset
                        table.insert(childList, childPlayState)
                    end
                end
            end
        end
    end
end

---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
---@param playState LBattleSkillPlayState
function LBattleSkillActBullet.ExecuteNormalBullet(player, effData, playState)
    local obj = player:GetTargetAtkUnitView()
    local effRes = effData.effRes --光效名字
    --local effTarget = effData.effTarget
    local moveSpeed = effData.moveSpeed * 0.01 -- 子弹飞行速度(配置表是像素这里要转换成米)
    local bulletTrack = effData.bulletTrack -- 子弹飞行轨迹
    local dissipateTime = effData.dissipateTime --光效消散时间
    local offsetStart = effData.effOffsetStart --偏移
    local bulletCdTime = effData.bulletCdTime or 0 --多个子弹的延迟射出间隔
    --local playNum = effData.playNum or {} --单个子弹分解次数
    local excursionIObject = effData.excursionIObject or 0
    local effStartType = effData.effStartType or 1

    local _viewMgr = player:GetViewMgr()
    local _heroOffsetPointList = player:GetHeroOffsetPointList()

    local curBulletCdTime = 0

    if moveSpeed <= 0 then
        if LOG_INFO_ENABLED then
            printError("battle", "wrong speed %s", tostring(effData.refId))
        end
        moveSpeed = 1
    end

    local offsetEnd = effData.effOffsetEnd
    local bulletTarPosList = {}

    local atkDir = obj:GetDirection()
    local atkPos = obj:GetPosition()
    local atkSide = obj:GetTeamIdx()

    local bulletData = player:FormatEffectData(effData)
    local dataList = {}
    if bulletData then
        table.insert(dataList,bulletData)
    end

    local effectRootTrans = _viewMgr:GetEffectRootTrans()
    --local effectPos
    --
    --if atkDir == LFightConst.DIRECTION_LEFT then
    --	--朝左
    --	effectPos = Vector3(atkPos.x - offsetStart.x, atkPos.y + offsetStart.y, 0)
    --else
    --	--朝右
    --	effectPos = Vector3(atkPos.x + offsetStart.x, atkPos.y + offsetStart.y, 0)
    --end

    local effectCtrl = _viewMgr:GetEffectCtrl()

    --子弹都是从自身位置创建，跟自身方向相同
    local moveTimeList = {}
    local maxMoveTime = 0

    for k, v in ipairs(dataList) do

        local defaultPos = player:GetEffStartPos(effStartType,atkSide,atkPos)
        local effectPos = nil
        if atkDir == LFightConst.DIRECTION_LEFT then
            --朝左
            effectPos = Vector3(defaultPos.x - offsetStart.x, defaultPos.y + offsetStart.y, 0)
        else
            --朝右
            effectPos = Vector3(defaultPos.x + offsetStart.x, defaultPos.y + offsetStart.y, 0)
        end

        local pos = v.pos
        --受击的 和 攻击的朝向相反的
        if atkDir == LFightConst.DIRECTION_RIGHT then
            pos.x = pos.x - offsetEnd.x
        else
            pos.x = pos.x + offsetEnd.x
        end

        if excursionIObject == 1 then
            local randomNum = _heroOffsetPointList[math.random(1,5)]  -- 目标人物偏移值，策划没有设置effOffsetEnd的前提下，0.1-0.3的区间范围：脚底，躯干，头顶
            pos.y = pos.y + randomNum
        else
            pos.y = pos.y + offsetEnd.y
        end

        pos.z = 0

        -- 弹道落点列表
        local point = pos:Clone()
        bulletTarPosList[k] = point

        local scale = player:GetScale()
        if scale and scale > 1 then
            effectPos.y = effectPos.y * scale
        end

        --计算出时间
        local moveTime = (Vector3.Distance(effectPos, pos) / moveSpeed)

        local effect = effectCtrl:MakeBattleSkillEffectObj(effectRootTrans, effRes, effectPos, atkDir, curBulletCdTime, moveTime, dissipateTime)
        effect:SetBullet(true, pos, moveTime, bulletTrack,k)
        local para =
        {
            isUpperLayer= player:IsUpperLayer(v.tarId),
            scale = scale
        }
        effect:SetEffectPara(para)
        effectCtrl:AddEffect(effect)

        moveTime = moveTime + curBulletCdTime
        if moveTime > maxMoveTime then
            maxMoveTime = moveTime
        end

        table.insert(moveTimeList, moveTime)

        --if v.isSingleBulletMuti then
        --	bulletCdTime = k <= #playNum and playNum[k] or playNum[#playNum]
        --	-- 单个目标多个子弹的延迟射出间隔
        --	curBulletCdTime = curBulletCdTime + bulletCdTime
        --else
        -- 多个目标的子弹的延迟射出间隔
        curBulletCdTime = curBulletCdTime + bulletCdTime
        --end
    end

    local nextPlayList = effData.nextPlayList

    local childList = playState.childList
    if not childList then
        return
    end

    --不嵌套子列表
    local startTime = playState.startTime
    for k, v in ipairs(nextPlayList) do
        local childStartTime = startTime + maxMoveTime + v.delayTime
        local childPlayState = player:GenerateChildPlayState(v, childStartTime, childStartTime + v.playTime)
        table.insert(childList, childPlayState)
    end

end


---@param player LBattleSkillPlayer
---@param effData LSkillEffectData
function LBattleSkillActBullet.FormatBulletData(player, effData)
    local obj = player:GetTargetAtkUnitView()
    if not obj then
        return
    end

    local dataList = {}
    local playNum = effData.playNum
    local viewMgr = player:GetViewMgr()
    local dataMgr = viewMgr:GetDataMgr()

    --2=每一个目标
    local skillHurtList = player:GetSkillHurtDataList()
    local skillEffId = player:GetSkillEffId()
    local vfxRefId = effData.refId
    local isMultiBullet,vfxIndex = dataMgr:IsMultiBulletShow(skillEffId,vfxRefId) --多个攻击特效，同一目标多个伤害
    local clientMulti = not table.isempty(playNum) and #playNum > 0  --一个攻击特效，多段伤害飘字表现

    -- 特殊多段子弹类型
    if clientMulti then  ---客户端表现多段
    local groupIndex = 1   ---根据不同目标划分子弹组
        for k,v in ipairs(skillHurtList) do
            local id = nil
            for k1,v1 in ipairs(v) do
                if v1.hitHurt then
                    id = v1.hitHurt.eId
                    break
                end
            end

            local cnt = #playNum +1
            for i=1,cnt do
                local tempData =
                {
                    tarId=id,
                    groupIndex = groupIndex,
                    hurtDataType = 1,--实际是一次飘字
                    hurtDataIndex = i, --子弹序号
                }

                local groupDataList = dataList[groupIndex] or {}
                dataList[groupIndex] = groupDataList
                table.insert(groupDataList,tempData)
            end
            groupIndex = groupIndex + 1
        end
    elseif isMultiBullet then --根据伤害次数计算子弹数
        local groupIndex = 1
        for k,v in ipairs(skillHurtList) do
            local hurtData = v[vfxIndex]
            if hurtData then
                local targetId = hurtData.hitHurt.eId
                local tempData = {
                    tarId=targetId,
                    groupIndex = groupIndex,
                    hurtDataType = 2,
                    hurtDataIndex = vfxIndex, --子弹序号
                }
                local groupDataList = dataList[groupIndex] or {}
                dataList[groupIndex] = groupDataList
                table.insert(groupDataList,tempData)
            end
            groupIndex = groupIndex + 1
        end
    else
        for k,v in ipairs(skillHurtList) do
            for k1,v1 in ipairs(v) do
                local id = v1.hitHurt.eId
                local tempData =
                {
                    tarId=id,
                    groupIndex = k,
                    hurtDataType = 3, --单独多次飘字
                    hurtDataIndex = k1, --子弹序号
                }
                local groupDataList = dataList[k] or {}
                dataList[k] = groupDataList
                table.insert(groupDataList,tempData)
            end
        end
    end

    return dataList

end

return LBattleSkillActBullet